function nextBusinessDayAt8am(from) {
  const dow = from.weekday;
  let daysToAdd = 1;
  if (dow === 5) daysToAdd = 3;  // viernes → lunes
  if (dow === 6) daysToAdd = 2;  // sábado → lunes
  return from.plus({ days: daysToAdd }).set({ hour: 8, minute: 0, second: 0, millisecond: 0 });
}

return items.map(item => {
  const cfg = $items('CONFIG INICIAL UTPL', 0, 0)[0].json.cfg;
  const db = item.json || {};
  let out = { ...db };

  // Determina la hora actual en la zona horaria del proyecto (America/Guayaquil)
  const now = DateTime.now().setZone(cfg.policy.TZ);
  const dow = now.weekday;          // 1=lunes ... 7=domingo
  const todayIso = now.toFormat('yyyy-MM-dd');
  const nowTime = now.toFormat('HH:mm');

  out.puedeLlamar = false;
  out.estado_flujo = db.estado_flujo || cfg.states.pending;

  //---- DOMINGO: reprograma al lunes 8am ----
  if (dow === 7) {
    const nextMonday = nextBusinessDayAt8am(now);
    out.status_sugerido = 'REINTENTAR';
    out.fecha_reagenda = nextMonday.toISO();
    out.reintentar_iso = out.fecha_reagenda;
    return { json: out };
  }

  // ---- FERIADOS: reprograma al siguiente dia habil 8am ----
  const isHoliday = cfg.policy.holidays.includes(todayIso);
  if (isHoliday) {
    out.status_sugerido = 'REINTENTAR';
    const nextDay = nextBusinessDayAt8am(now);
    out.fecha_reagenda = nextDay.toISO();
    out.reintentar_iso = out.fecha_reagenda;
    return { json: out };
  }

  // ---- LIMITE DE INTENTOS TOTALES (16): marca como AGOTADO ----
  const intentosRaw = Number(db.intentos_llamada) || 0;
  out.intentos_llamada = intentosRaw;

  if (intentosRaw >= cfg.policy.maxLifetimeTries) {
    out.estado_flujo = cfg.states.done;
    out.status_sugerido = 'AGOTADO';
    out.fecha_reagenda = null;
    return { json: out };
  }

  // ---- RESPETAR fecha_reagenda (cooldown entre intentos) ----
  if (db.fecha_reagenda && new Date(db.fecha_reagenda) > new Date()) {
    out.status_sugerido = 'REINTENTAR';
    out.fecha_reagenda = db.fecha_reagenda;
    return { json: out };
  }

  // ---- ASISTENTE VAPI segun modalidad (LINEA / POSGRADO / TECNOLOGICO) ----
  const modalidad = String(db.modalidad ?? '').trim().toUpperCase();
  out.assistant_id = cfg.agents[modalidad] || cfg.agents['MODALIDAD EN LINEA'] || '';

  // ---- VENTANA DE LLAMADA actual y contadores ----
  const winStamp = String(db.win_stamp || '');
  const winTries = Number(db.win_tries) || 0;
  out.win_stamp = winStamp;
  out.win_tries = winTries;
  out.modo_operativo = 'normal';

  const dayStr = String(dow);
  const todayWindows = cfg.policy.windows.filter(w => w.days.split(',').includes(dayStr));

  // ---- SIN VENTANA PARA HOY (ej. sabado): reprograma al siguiente dia habil 8am ----
  if (todayWindows.length === 0) {
    out.status_sugerido = 'REINTENTAR';
    const nextDay = nextBusinessDayAt8am(now);
    out.fecha_reagenda = nextDay.toISO();
    out.reintentar_iso = out.fecha_reagenda;
    return { json: out };
  }

  // ---- BUSCA LA VENTANA (MAÑANA/TARDE/NOCHE) en la que estamos ----
  let currentWindowIdx = -1;
  let currentWindow = null;

  for (let i = 0; i < todayWindows.length; i++) {
    const w = todayWindows[i];
    if (nowTime >= w.start && nowTime <= w.end) {
      currentWindowIdx = i;
      currentWindow = w;
      break;
    }
  }

  // ---- FUERA DE HORARIO LABORAL: reprograma a la proxima ventana o al dia siguiente habil ----
  if (!currentWindow) {
    let upcomingWindow = null;
    for (let i = 0; i < todayWindows.length; i++) {
      if (nowTime < todayWindows[i].start) {
        upcomingWindow = todayWindows[i];
        break;
      }
    }

    if (upcomingWindow) {
      out.status_sugerido = 'REINTENTAR';
      const [h, m] = upcomingWindow.start.split(':').map(Number);
      out.fecha_reagenda = now.set({ hour: h, minute: m, second: 0, millisecond: 0 }).toISO();
      out.reintentar_iso = out.fecha_reagenda;
    } else {
      // ya pasaron todas las ventanas de hoy
      out.status_sugerido = 'REINTENTAR';
      const nextDay = nextBusinessDayAt8am(now);
      out.fecha_reagenda = nextDay.toISO();
      out.reintentar_iso = out.fecha_reagenda;
    }
    return { json: out };
  }

  // ---- REGLA 3x3: controla los intentos dentro de la ventana actual ----
  const stampForWindow = `${currentWindow.id}_${todayIso}`;

  if (winStamp !== stampForWindow) {
    // Primera llamada en esta ventana → reinicia contador
    out.win_stamp = stampForWindow;
    out.win_tries = 0;
    out.puedeLlamar = true;
  } else if (winTries < cfg.policy.maxWindowTries) {
    // Aun quedan intentos en esta ventana
    out.puedeLlamar = true;
  } else {
    // Se agotaron los 3 intentos de esta ventana → pasa a la siguiente o al dia siguiente habil
    const nextIdx = currentWindowIdx + 1;
    if (nextIdx < todayWindows.length) {
      out.status_sugerido = 'REINTENTAR';
      const nextWin = todayWindows[nextIdx];
      const [h, m] = nextWin.start.split(':').map(Number);
      out.fecha_reagenda = now.set({ hour: h, minute: m, second: 0, millisecond: 0 }).toISO();
      out.reintentar_iso = out.fecha_reagenda;
    } else {
      out.status_sugerido = 'REINTENTAR';
      const nextDay = nextBusinessDayAt8am(now);
      out.fecha_reagenda = nextDay.toISO();
      out.reintentar_iso = out.fecha_reagenda;
    }
  }

  return { json: out };
});

return items.map(item => {
  const db = item.json || {};
  let phones = [];
  const cfg = $items('CONFIG INICIAL UTPL', 0, 0)[0].json.cfg;
  const CC = cfg.policy.CC || '+593';
  const ccDigits = CC.replace(/\D/g, ''); // '593' — digitos del codigo de pais
  const phoneFields = cfg.policy.phoneFields || ['telefono1', 'telefono2', 'telefono3', 'telefono4', 'telefono5', 'telefono6'];
  const seen = new Set(); // evita numeros duplicados

  for (const field of phoneFields) {
    const raw = String(db[field] || '');
    const val = raw.replace(/\D/g, '');
    if (val.length < 9) continue;

    let e164 = val;
    if (val.startsWith('0')) {
      // 0999999999 → +593999999999
      e164 = CC + val.substring(1);
    } else if (!val.startsWith(ccDigits)) {
      // 999999999 → +593999999999
      e164 = CC + val;
    }
    // si ya empieza con 593 o +593, se deja tal cual

    if (!seen.has(e164)) {
      seen.add(e164);
      phones.push({ field, e164 });
    }
  }

  const tIndex = Number(db.telefono_index ?? 0);
  let selected = null;

  if (phones.length > 0) {
    const idx = tIndex % phones.length;
    selected = phones[idx];
  }

  item.json.phones_parsed = phones;
  item.json.selected_phone = selected;
  item.json.telefono_actual = selected ? selected.e164 : '';
  item.json.isOutOfNumbers = selected === null;
  item.json.hasPhonesOutsideWindow = false;

  return item;
});

return items.map(item => {
  const lead = item.json;

  lead.snapshot_estado_flujo = lead.estado_flujo;
  lead.snapshot_fecha_reagenda = lead.fecha_reagenda;
  lead.snapshot_intentos_llamada = lead.intentos_llamada;
  lead.snapshot_win_tries = lead.win_tries;
  lead.snapshot_telefono_index = lead.telefono_index;
  lead.snapshot_win_stamp = lead.win_stamp;
  lead.snapshot_fecha_ultima_llamada = lead.fecha_ultima_llamada;

  return item;
});

return items.map(item => {
  const lead = item.json;
  const cfg = $items('CONFIG INICIAL UTPL', 0, 0)[0].json.cfg;

  if (lead.hasPhonesOutsideWindow) {
    const t = new Date();
    t.setMinutes(t.getMinutes() + Number(cfg.policy.offHoursWait || 30));
    lead.estado_flujo = cfg.states.retry;
    lead.status_sugerido = 'REINTENTAR';
    lead.fecha_reagenda = t.toISOString();
    lead.reintentar_iso = lead.fecha_reagenda;
    return item;
  }

  lead.estado_flujo = cfg.states.done;
  lead.status_sugerido = 'FINAL';
  lead.fecha_reagenda = null;
  return item;
});

