={{ (() => {
  const cfg = $items('CONFIG INICIAL UTPL', 0, 0)[0].json.cfg;

  // id_negocio del item actual o del lead original si venimos de error
  const raw = String($json.id_negocio ?? $items('BUSCA Y BLOQUEA REGISTRO', 0, 0)[0].json.id_negocio ?? '').trim();
  if (!raw) return 'SELECT \'skip_fallback_sin_id\' AS status';

  // Escapa comillas simples para evitar inyeccion SQL
  const esc = s => String(s ?? '').replace(/'/g, "''");

  // Si CAPTURA SNAPSHOT corrio, restaura los valores originales del lead
  if ($json.snapshot_estado_flujo !== undefined) {
    const snapFechaReagenda = $json.snapshot_fecha_reagenda;
    const snapFechaUlt = $json.snapshot_fecha_ultima_llamada;
    const snapWinStamp = $json.snapshot_win_stamp;

    return `
      UPDATE public.utpl_registros
      SET estado_flujo = '${esc(($json.snapshot_estado_flujo === 'EN_PROCESO') ? cfg.states.pending : ($json.snapshot_estado_flujo ?? cfg.states.pending))}',
          fecha_reagenda = ${snapFechaReagenda ? `'${esc(String(snapFechaReagenda))}'::timestamptz` : 'NULL'},
          intentos_llamada = ${$json.snapshot_intentos_llamada ?? 'NULL'},
          win_tries = ${$json.snapshot_win_tries ?? 'NULL'},
          telefono_index = ${$json.snapshot_telefono_index ?? 'NULL'},
          win_stamp = ${snapWinStamp ? `'${esc(String(snapWinStamp))}'` : 'NULL'},
          fecha_ultima_llamada = ${snapFechaUlt ? `'${esc(String(snapFechaUlt))}'::timestamptz` : 'NULL'},
          updated_at = now()
      WHERE id_negocio = '${esc(raw)}'
      RETURNING *;
    `;
  }

  // Sin snapshot: resetea el lead a PENDIENTE con contadores en cero
  return `
    UPDATE public.utpl_registros
    SET estado_flujo = '${cfg.states.pending}',
        fecha_reagenda = NULL,
        intentos_llamada = 0,
        win_tries = 0,
        telefono_index = 0,
        win_stamp = NULL,
        fecha_ultima_llamada = NULL,
        updated_at = now()
    WHERE id_negocio = '${esc(raw)}'
    RETURNING *;
  `;
})() }}

