const escapeXml = function(str) {
  return String(str || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;').replace(/'/g, '&apos;');
};

return items.map(item => {
  const cfg = $items('CONFIG INICIAL UTPL', 0, 0)[0].json.cfg;
  const crm = cfg.crmUtpl || {};

  const idNegocio = String(item.json.id_negocio || '').trim();
  const dealid = String(item.json.id_interno_negocio || '');
  const fechaUltima = item.json.fecha_ultima_llamada;

  let hsTimestamp = '';
  if (fechaUltima) {
    try {
      const dt = DateTime.fromISO(String(fechaUltima)).setZone(cfg.policy.TZ);
      if (dt.isValid) hsTimestamp = dt.toFormat('yyyy-MM-dd HH:mm:ss');
    } catch (e) {}
  }
  if (!hsTimestamp) {
    hsTimestamp = DateTime.now().setZone(cfg.policy.TZ).toFormat('yyyy-MM-dd HH:mm:ss');
  }

  const dealstage = (crm.dealstage && crm.dealstage.NIN) || '1020923926';
  const defAg = (crm.defaultDisposition && crm.defaultDisposition.agotado) || {};
  const disposition = defAg.disposition || 'fa9b4696-95d1-4b4a-906f-4b0b7b7f155b';
  const subEstado = defAg.subEstado || 'NIN - No Localizable';

  item.json.crmHsTimestamp = hsTimestamp;

  item.json.soapXml = `<?xml version="1.0" encoding="utf-8"?>
<soap:Envelope xmlns:xsi="http://www.w3.org/2001/XMLSchema-instance" xmlns:xsd="http://www.w3.org/2001/XMLSchema" xmlns:soap="http://schemas.xmlsoap.org/soap/envelope/">
  <soap:Body>
    <RegistrarLLamada xmlns="http://tempuri.org/">
      <codigo_negocio>${escapeXml(idNegocio)}</codigo_negocio>
      <dealstage>${escapeXml(dealstage)}</dealstage>
      <hs_call_disposition>${escapeXml(disposition)}</hs_call_disposition>
      <hs_call_body>${escapeXml('Maximo de intentos alcanzado sin contacto exitoso')}</hs_call_body>
      <agent_name>${escapeXml(crm.agentName || 'ARIA UTPL')}</agent_name>
      <hs_call_duration>0</hs_call_duration>
      <sales_stage_detail>${escapeXml(subEstado)}</sales_stage_detail>
      <commitment_date></commitment_date>
      <dealid>${escapeXml(dealid)}</dealid>
      <hs_timestamp>${escapeXml(hsTimestamp)}</hs_timestamp>
      <scheduling_date></scheduling_date>
    </RegistrarLLamada>
  </soap:Body>
</soap:Envelope>`;

  return item;
});

return items.map(item => {
  const cfg = $items('CONFIG INICIAL UTPL', 0, 0)[0].json.cfg;
  const crm = cfg.crmUtpl || {};
  const prevItems = $items('PREPARA SOAP XML AGOTADO', 0, 0);
  const prev = prevItems.length > 0 ? prevItems[0].json : {};
  const body = String(item.json.response || item.json.data || item.json.body || '');
  const hc = body.match(/<httpCode>(\d+)<\/httpCode>/);
  const ir = body.match(/<idreturn>([^<]+)<\/idreturn>/);
  const m1 = body.match(/<messagews1>([^<]*)<\/messagews1>/);
  const m2 = body.match(/<messagews2>([^<]*)<\/messagews2>/);
  const m3 = body.match(/<messagews3>([^<]*)<\/messagews3>/);

  item.json.crmHttpCode = hc ? hc[1] : null;
  item.json.crmIdReturn = ir ? ir[1] : null;
  item.json.crmSuccess = item.json.crmHttpCode && String(item.json.crmHttpCode).startsWith('2');

  if (!item.json.crmSuccess) {
    item.json.crmError = [m1 ? m1[1] : null, m2 ? m2[1] : null, m3 ? m3[1] : null].filter(Boolean).join(' | ');
  }

  const idNegocio = String(item.json.id_negocio || prev.id_negocio || '').trim();
  const idInterno = String(item.json.id_interno_negocio || prev.id_interno_negocio || '');
  const soapXml = String(item.json.soapXml || prev.soapXml || '');
  const hsTimestamp = String(item.json.crmHsTimestamp || prev.crmHsTimestamp || '');

  const esc = function(s) { return String(s || '').replace(/'/g, "''"); };
  const deS = (crm.dealstage && crm.dealstage.NIN) || '1020923926';
  const defAg = (crm.defaultDisposition && crm.defaultDisposition.agotado) || {};
  const dis = defAg.disposition || 'fa9b4696-95d1-4b4a-906f-4b0b7b7f155b';
  const sst = defAg.subEstado || 'NIN - No Localizable';
  const cuerpo = 'Maximo de intentos alcanzado sin contacto exitoso';

  item.json.crmInsertQuery = `INSERT INTO public.utpl_crm (id_negocio, flujo_origen, nomenclatura, dealstage, hs_call_disposition, sales_stage_detail, agent_name, hs_call_duration, hs_call_body, commitment_date, dealid, hs_timestamp, scheduling_date, soap_xml, http_code, id_return, error_messages) VALUES ('${esc(idNegocio)}', 'Llamadas', 'NIN', '${esc(deS)}', '${esc(dis)}', '${esc(sst)}', '${esc(crm.agentName || 'ARIA UTPL')}', '0', '${esc(cuerpo)}', NULL, '${esc(idInterno)}', '${esc(hsTimestamp)}', NULL, '${esc(soapXml)}', '${esc(item.json.crmHttpCode)}', '${esc(item.json.crmIdReturn)}', '${esc(item.json.crmError)}')`;

  return item;
});

return items.map(item => {
  const tokenRow = item.json;
  const token = tokenRow.value || null;
  const expiresAt = tokenRow.expires_at || null;

  let needsRefresh = true;
  if (token && expiresAt) {
    if (new Date(expiresAt) > new Date()) {
      needsRefresh = false;
      item.json.altivaToken = token;
    }
  }

  item.json.tokenNeedsRefresh = needsRefresh;
  return item;
});

return items.map(item => {
  const cfg = $items('CONFIG INICIAL UTPL', 0, 0)[0].json.cfg;

  item.json.altivaBody = {
    nuic: String(item.json.id_interno_negocio || ''),
    nombre_corto_campania: String(item.json.nombre_corto_campania || cfg.altiva.nombreCampania || ''),
    nodo: '1'
  };

  const token = item.json.altivaToken || (item.json.data && item.json.data.access_token) || item.json.value || '';
  if (!item.json.altivaToken && item.json.data && item.json.data.access_token) {
    item.json.altivaToken = String(item.json.data.access_token);
  } else if (!item.json.altivaToken && item.json.value) {
    item.json.altivaToken = String(item.json.value);
  }

  return item;
});

return items.map(item => {
  const body = item.json.response || item.json;
  let status = null, message = '';
  try {
    const parsed = typeof body === 'string' ? JSON.parse(body) : body;
    status = parsed.estado || null;
    message = parsed.mensaje || '';
  } catch (e) {
    message = String(body || '').substring(0, 200);
  }

  item.json.altivaStatus = status;
  item.json.altivaMessage = message;
  item.json.altivaSuccess = status === 200;

  return item;
});

return items.map(item => {
  const cfg = $items('CONFIG INICIAL UTPL', 0, 0)[0].json.cfg;
  const lead = item.json;

  // 1. Nombre completo
  lead.nombre_completo = `${lead.nombre || ''} ${lead.apellido || ''}`.trim();

  // 2. Assistant ID según modalidad
  const modalidad = String(lead.modalidad ?? '').trim().toUpperCase();
  lead.assistant_id = cfg.agents[modalidad] || cfg.agents['MODALIDAD EN LINEA'];
  lead.modo_operativo = 'normal';

  // 3. Filtrar teléfonos válidos (misma lógica que PROCESA TELEFONOS)
  const phoneFields = cfg.policy.phoneFields;
  const CC = cfg.policy.CC || '+593';
  const ccDigits = CC.replace(/\D/g, '');
  const validPhones = [];

  for (const field of phoneFields) {
    const raw = String(lead[field] || '');
    const digits = raw.replace(/\D/g, '');
    if (digits.length < 9) continue;

    let e164 = digits;
    if (digits.startsWith('0')) {
      e164 = CC + digits.substring(1);
    } else if (!digits.startsWith(ccDigits)) {
      e164 = CC + digits;
    }

    validPhones.push({ field, e164 });
  }

  // 4. Seleccionar según telefono_index (con fallback si el apuntado está vacío)
  const tIndex = Number(lead.telefono_index ?? 0);
  let selected = null;

  if (validPhones.length > 0) {
    const idx = tIndex % validPhones.length;
    selected = validPhones[idx];
  }

  lead.telefono_actual = selected ? selected.e164 : '';
  lead.selected_phone = selected;
  lead.isOutOfNumbers = selected === null;

  return item;
});
